import React, { useState } from 'react';
import EndPage from './EndPage';
import MainGamePAge from './MainGamePage';
import NewGame from './NewGame';
import StartPlaying from './StartPlaying';

const pages = { newGame: "newGame", firstsDraw: "firstDraw", mainGamePage: "mainGamePage" , endPage:"endGame" }
export default function GameBord(props) {
    const [playerDec, setPlayerDec] = useState([])
    const [computerDec, setComputerDec] = useState([])
    const [readyToStart, setReadyToStart] = useState(false)
    const [start, setStart] = useState(false)
    const [roundNumber, setRoundNumber] = useState(0)
    const [gameWon, setGameWon] = useState(false)
    const [pScore, setPScore] = useState(0)
    const [cScore, setCScore] = useState(0)
    const [pImg, setPImg] = useState("")
    const [cImg, setCImg] = useState("")
    const [currentPage, setCurrentPage] = useState("newGame")
    const totalCards = 52
    const copyFromEatchCard = 4

    let createDec = () => {
        let mainDec = []
        for (let i = 1; i <= totalCards / copyFromEatchCard; i++) {
            for (let x = 0; x < copyFromEatchCard; x++) {
                mainDec.push(i)
            }
        }
        let pDec = []
        let cDec = []
        let rnd = 0
        while (mainDec.length > 0) {
            rnd = getRandomNum(mainDec.length)
            pDec.push(mainDec[rnd])
            mainDec.splice(rnd, 1)
            rnd = getRandomNum(mainDec.length)
            cDec.push(mainDec[rnd])
            mainDec.splice(rnd, 1)

        }
        console.log();
        setPlayerDec(pDec)
        setComputerDec(cDec)
        setCurrentPage("firstDraw")
    }

    let getRandomNum = (max) => {
        return Math.floor(Math.random() * max)
    }

    let startTheGame = () => {
        if (computerDec[roundNumber] > playerDec[roundNumber])
            setCScore(cScore + 1)
        else if (computerDec[roundNumber] < playerDec[roundNumber])
            setPScore(pScore + 1)
        console.log(playerDec)
        console.log(computerDec)
        setImg()
        setCurrentPage(pages.mainGamePage)
    }


    let nextCard = () => {
        setRoundNumber(roundNumber + 1)
        console.log(roundNumber)

        if (computerDec[roundNumber] > playerDec[roundNumber]) {
            setCScore(cScore + 1)
        } else if (computerDec[roundNumber] < playerDec[roundNumber]) {
            setPScore(pScore + 1)
        }
        setImg()
    }


    let setImg = () => {
        let a = "./cards/" + computerDec[roundNumber] + "-" + getR() + ".png"
        setCImg(a)
        let b = "./cards/" + playerDec[roundNumber] + "-" + getR() + ".png"
        setPImg(b)
    }



    let buttons = () => {
        console.log(roundNumber)
        if (roundNumber == ((totalCards / 2)-1)) {
            return <button onClick={() => finish()} >Finish</button>
        }
        else {
            return <button onClick={() => nextCard()} >Next draw!</button>
        }
    }



    let finish = () => {
        if (computerDec[roundNumber] > playerDec[roundNumber]) {
            setCScore(cScore + 1)
        }
        else if (computerDec[roundNumber] < playerDec[roundNumber]) {
            setPScore(pScore + 1)
        }
        if (pScore < cScore) {
            setGameWon(true)
            sendInfo(true)
        }
        else {
            setGameWon(false)
            sendInfo(false)
        }
        setCurrentPage("endGame")
    }



    let changeUser = () => {
        props.currentPage(props.pages.home)
        setPlayerDec([])
        setComputerDec([])
        setReadyToStart(false)
        setStart(false)
        setRoundNumber(0)
        setPScore(0)
        setCScore(0)

    }
    let rematch = () => {
        props.currentPage(props.pages.game)
        setPlayerDec([])
        setComputerDec([])
        setReadyToStart(false)
        setStart(false)
        setRoundNumber(0)
        setPScore(0)
        setCScore(0)

    }

    let scores = () => {
        if (gameWon)
            return <h1>you won this time!</h1>
        else
            return <h1>you lost!</h1>
    }



    let getR = () => {
        return Math.floor(Math.random() * (4 - 1) + 1);
    }


    let sendImg = (img) => {
        return <img src={img} />
    }



    let sendInfo = (didWon) => {
        props.saveInfo(props.playerName, didWon)
    }
    let gamePages = () => {
        if (currentPage == "newGame") {
            return (<NewGame createDec={createDec} />)
        }
        else if (currentPage == "firstDraw") {
            return (<StartPlaying startTheGame={startTheGame} />)

        }
        else if (currentPage == "mainGamePage") {
            return (<MainGamePAge roundNumber={roundNumber} totalCards={totalCards} playerName={props.playerName}
                pScore={pScore} cScore={cScore} sendImg={sendImg} buttons={buttons} />)

        }
        else if (currentPage == "endGame") {
            return (<EndPage playerName={props.playerName} theList={props.theList} rematch={rematch} changeUser={changeUser}/>)
        }
    }

    return (
        gamePages()
    )
}
